INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-appraiser-moex-00413', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '昔人有睹雁翔者，將援弓射之，曰：「獲則烹。」其弟爭曰：「舒雁烹宜，翔雁燔宜。」竟鬥而訟於社 伯，社伯請剖雁，烹、燔半焉。已而索雁，則凌空遠矣。（劉元卿《賢奕編．兄弟爭雁》） 根據上文，下列敘述錯誤的選項是：', '["文中言「將」援弓射之，獲「則」烹，皆假設之意，表示事情尚未發生", "「竟」鬥而訟於社伯，是說兄弟居然為了還未到手的雁爭吵到社伯那裡去", "「已而」索雁，「則」凌空遠矣，「已而」和「則」都是指事情已經發生過了", "「社伯請剖雁，烹、燔半焉」，意謂社伯同意弟弟「舒雁烹宜，翔雁燔宜」的說法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00414', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '承上題，下列敘述，最貼近此一故事寓意的選項是：', '["擇善固執，力爭到底", "空談無益，坐失良機", "規劃遠景，量力而為", "手足情深，不宜興訟"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00415', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '北齊 徐之才後封西陽王，尚書王元景嘗戲之才曰：「人名之才，有何義理？以僕所解，當是乏才。」之才即 應聲嘲元景姓曰：「王之為字，有言為，近犬便狂，加頸足而為馬，施角尾而成羊。」元景遂無以對。 文中徐之才與王元景的對話，是一種：', '["相互詬罵", "相互嘲弄", "相互辯論", "相互切磋說話藝術"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00416', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '對於我來說，父親還有另一個榜樣，就是一份自在真實的謙抑。畢其一生，父親固然絕沒有因家世的寒 薄而來的、任何形式的自卑，尤其沒有常見於刻苦自學成材的人難免的驕躁與刻薄。他從未因自己的知 識見解比別人深刻而得理奪人。即使他的孩子在文學上粗有虛聲，父親從來不曾在我跟前揄揚他所喜愛 的一些我的作品，更從不曾在外人對我的文學的褒聲中附和。他畢其一生從容而自在地隱藏著他過人的 資質、識見和高潔的心靈。 根據上文，下列對「父親」的描述，最適合的選項是：', '["不以物喜，不以己悲", "隱惡揚善，行俠仗義", "光明磊落，真誠惻怛", "不卑不亢，謙和內斂"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00417', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '下列五幅對聯，就其內容判斷，依序最適合張貼於那些處所？ 【甲】如得其情，則哀矜而勿喜∕有條不紊，若靜網之在綱 【乙】思患預防，可冀烽煙永息∕賞勤罰惰，免教宵小橫行 【丙】開源節流，要貴預期籌算∕量入為出，還需事先經營 【丁】涓滴入公家，恤商乃能裕課∕絲毫無流弊，克己方能正人 【戊】懷抱宏才，休言伯樂居何處∕胸存大志，願獻工夫在此時', '["立法院∕法院∕經濟部∕國稅局∕考試院", "法院∕警察機關∕經濟部∕財政部∕考試院", "法院∕警察機關∕財政部∕國稅局∕國家考場", "警察機關∕立法院∕國稅局∕財政部∕國家考場"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00418', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '閱讀下文回答問題： 「只是一瞥，只在鞦韆盪高去的那一剎，世界便迎面而來。也許視線只不過以二公里為半徑，向四面 八方擴充了一點點，然而那一點是多麼令人難忘啊！人類的視野不就是那樣一點點地拓寬的嗎？女子 在那如電光石火的剎那窺見了世界和春天。而那時候，隨風鼓脹的，又豈是她繡花的裙襬呢？」（張 曉風〈鞦韆上的女子〉）上引文字中，盪鞦韆對女子的意義是：', '["滿足窺伺的好奇心", "看見廣闊的未知世界", "展現青春飛揚的風姿", "把握剎那即永恆的真諦"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00419', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '符號是否也有汗水？「中國製造」讓我們想起曾幾何時台灣乃是世界重要的玩具生產國，多少人犧牲了童 年，在客廳即工廠裡剪裁絨毛布塊，為台灣的經濟奇蹟出一份力；「中國製造」也讓我們間接想起迪士尼 的卡通週邊產品，在勞力密集的第三世界捅下的許多漏子：雇用童工，不遵守最低工時與基本工資，慘無 人道的「苦力工廠」（Sweat shop）等，在未被揭露之前，我們哪裡知道，一些孩子們的幸福快樂，乃是 由另一群犧牲了幸福快樂的孩子們所創造的殘忍事實。 根據上文，下列何者不是本文作者對「中國製造」的聯想？', '["第三世界國家的勞工問題", "台灣經濟發展的艱辛歷程", "「台灣製造」被「中國製造」所取代", "一些孩子的幸福快樂背後隱藏了殘忍的事實"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00420', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '同上題，作者提出「符號是否也有汗水」，表示她所關心的是商品背後的那個問題？', '["民眾消費力差距懸殊", "生產制度的不合理性", "兩岸政經的相互角力", "勞資糾紛的頻繁發生"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00421', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '墨子往見楚王，勸他勿用公輸盤的雲梯攻打宋國，楚王曰：「善哉！雖然，公輸盤為我為雲梯，必取宋。」 （《墨子．公輸盤》） 以下即墨子、楚王、公輸盤三人承上文而來的對話，請按文意及邏輯判斷下列文字的排列次序：', '["公輸盤九設攻城之機變，子墨子九距之", "於是見公輸盤，子墨子解帶為城，以牒為械", "公輸盤之攻械盡，子墨子之守圉有餘", "公輸盤詘，而曰：「吾知所以距子矣，吾不言。」 子墨子亦曰：「吾知子之所以距我，吾不言。」"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00422', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '承上題，以下所引文字乃緊接在上一題排列的文字之後，□□處皆為同一詞語，根據文意判斷，□□內 最適切的詞語是： 楚王問其故，子墨子曰：「公輸子之意，不過欲□□。□□，宋莫能守，可攻也。然臣之弟子禽滑釐等三百 人，已持臣守圉之器在宋城上而待楚寇矣。雖□□，不能絕也。」楚王曰：「善哉！吾請無攻宋矣。」', '["攻城", "欺我", "殺臣", "棄攻 【甲】 桓公讀書於堂上，輪扁斲輪於堂下，釋椎鑿而上，問桓公曰：「敢問公之所讀者何言也？」公曰：「聖人 之言也。」曰：「聖人在乎？」公曰：「已死矣。」曰：「然則君之所讀者，古人之糟魄已夫。」桓公曰： 「寡人讀書，輪人安得議乎？有說則可，無說則死。」輪扁曰：「臣也，以臣之事觀之。斲輪，徐則甘而不 固，疾則苦而不入。不徐不疾，得之於手而應於心。口不能言，有數存焉於其間。臣不能以喻臣之子，臣之 子亦不能受之於臣，是以行年七十而老斲輪。古之人與其不可傳也，死矣，然則君之所讀者，古人之糟魄已 夫。」（莊子〈天道〉） 【乙】 余友李公擇，少時讀書於廬山 五老峰下白石庵之僧舍。公擇既去，而山中之人思之，指其所居為「李 氏山房」，藏書凡九千餘卷。公擇既已涉其流，探其源，採剝其華實，而咀嚼其膏味，以為己有，發於 文詞，見於行事，以聞名於當世矣。而書固自如也，未嘗少損。將以遺來者，供其無窮之求，而各足其 才分之所當得。是以不藏於家，而藏於其故所居之僧舍，此仁者之心也。 余既衰且病，無所用於世，惟將數年之間，盡讀其所未見之書，而廬山固所願遊而不得者，蓋將老焉。 盡發公擇之藏，拾其餘棄以自補，庶有益乎！而公擇求余文以為記，乃為一言，使來者知昔之君子見書 之難，而今之學者有書而不讀，為可惜也。（蘇軾〈李氏山房藏書記〉） 請依上文回答16至18題"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL)
